{
var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);

    var depth = GetFloat(parameters, "depth", 2f);
    var brightness = GetFloat(parameters, "brightness", 0.6f);
    var ambient = GetFloat(parameters, "ambient", 0.3f);
    var specular = GetFloat(parameters, "specular", 0.3f);
    var specularPower = GetFloat(parameters, "specularPower", 8f);
    var lightDir = GetChoice(parameters, "lightDirection", "topLeft");
    var lightAngle = GetFloat(parameters, "lightAngle", 0.785f);
    var heightSource = GetChoice(parameters, "heightSource", "alpha");
    var inner = GetBool(parameters, "innerBevel", true);

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);
    var useAlpha = heightSource == "alpha";

    // Light direction
    float lx, ly;
    switch (lightDir)
    {
        case "topRight": lx = 0.707f; ly = -0.707f; break;
        case "bottomLeft": lx = -0.707f; ly = 0.707f; break;
        case "bottomRight": lx = 0.707f; ly = 0.707f; break;
        case "top": lx = 0f; ly = -1f; break;
        case "custom": lx = MathF.Cos(lightAngle); ly = MathF.Sin(lightAngle); break;
        default: lx = -0.707f; ly = -0.707f; break; // topLeft
    }

    // Half-vector for Blinn-Phong specular (view direction = (0,0,1))
    var hx = lx;
    var hy = ly;
    var hz = 1f;
    var hLen = MathF.Sqrt(hx * hx + hy * hy + hz * hz);
    hx /= hLen; hy /= hLen; hz /= hLen;

    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);

        // Consistent height field: both center and neighbors use same source
        var hC = useAlpha ? a : SampleHeightFromLuminance(input, x, y);
        var hL = useAlpha ? SampleHeightFromAlpha(input, x - 1, y) : SampleHeightFromLuminance(input, x - 1, y);
        var hR = useAlpha ? SampleHeightFromAlpha(input, x + 1, y) : SampleHeightFromLuminance(input, x + 1, y);
        var hD = useAlpha ? SampleHeightFromAlpha(input, x, y - 1) : SampleHeightFromLuminance(input, x, y - 1);
        var hU = useAlpha ? SampleHeightFromAlpha(input, x, y + 1) : SampleHeightFromLuminance(input, x, y + 1);

        // Calculate normal from gradient
        var gx = (hR - hL) * depth;
        var gy = (hU - hD) * depth;
        if (!inner) { gx = -gx; gy = -gy; }

        var len = MathF.Sqrt(gx * gx + gy * gy + 1f);
        var nx = gx / len;
        var ny = gy / len;
        var nz = 1f / len;

        // Diffuse (Lambert)
        var ndotl = nx * lx + ny * ly + nz * 0.5f;
        ndotl = MathF.Max(0f, ndotl);
        var shade = ambient + ndotl * brightness;

        // Specular (Blinn-Phong)
        var ndoth = nx * hx + ny * hy + nz * hz;
        var spec = 0f;
        if (ndoth > 0f)
        {
            spec = specular * MathF.Pow(ndoth, specularPower);
        }

        shade = Math.Clamp(shade + spec, 0f, 1f);

        var nr = Math.Clamp(r * shade, 0f, 1f);
        var ng = Math.Clamp(g * shade, 0f, 1f);
        var nb = Math.Clamp(b * shade, 0f, 1f);

        output.SetPixel(x, y, nr, ng, nb, a);
    });

    return output;

private static float SampleHeightFromAlpha(PixelBuffer buffer, int x, int y)
{
    x = Math.Clamp(x, 0, buffer.Width - 1);
    y = Math.Clamp(y, 0, buffer.Height - 1);
    var (_, _, _, a) = buffer.GetPixel(x, y);
    return a;
}

private static float SampleHeightFromLuminance(PixelBuffer buffer, int x, int y)
{
    x = Math.Clamp(x, 0, buffer.Width - 1);
    y = Math.Clamp(y, 0, buffer.Height - 1);
    var (r, g, b, _) = buffer.GetPixel(x, y);
    return r * 0.299f + g * 0.587f + b * 0.114f;
    }
}
